import { useFavoriler } from "../context/FavoriContext";
import UrunCard from "../components/UrunCard";
import { useState } from "react";

export default function Favoriler() {
  const { favoriler } = useFavoriler();
  const [aktifKategori, setAktifKategori] = useState("tumu");

  const kategoriler = [...new Set(favoriler.map(u => u.kategori).filter(Boolean))];

  const filtrelenmisFavoriler =
    aktifKategori === "tumu"
      ? favoriler
      : favoriler.filter((u) => u.kategori === aktifKategori);

  return (
    <div className="p-6 max-w-screen-xl mx-auto">
      <h1 className="text-2xl font-bold mb-6">Favori Ürünlerim</h1>

      {favoriler.length === 0 ? (
        <p className="text-gray-600">Henüz favorilere ürün eklenmemiş.</p>
      ) : (
        <>
          <div className="mb-6">
            <label className="mr-3 font-semibold">Kategori:</label>
            <select
              value={aktifKategori}
              onChange={(e) => setAktifKategori(e.target.value)}
              className="border rounded px-3 py-1"
            >
              <option value="tumu">Tümü</option>
              {kategoriler.map((k, i) => (
                <option key={i} value={k}>
                  {k}
                </option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-6">
            {filtrelenmisFavoriler.map((urun) => (
              <UrunCard key={urun.id} urun={urun} />
            ))}
          </div>
        </>
      )}
    </div>
  );
}
